import{_ as a,O as r,H as n,f as d,k as i,i as o}from"./chunks/framework.Pt2pSV98.js";const f=JSON.parse('{"title":"术语知识测验","description":"检测你对 AI 核心术语的掌握程度，涵盖 LLM、Transformer、RAG、Agent 等核心概念","frontmatter":{"title":"术语知识测验","description":"检测你对 AI 核心术语的掌握程度，涵盖 LLM、Transformer、RAG、Agent 等核心概念","difficulty":"beginner"},"headers":[],"relativePath":"terms/quiz.md","filePath":"terms/quiz.md"}'),l={name:"terms/quiz.md"};function s(h,t,m,p,u,g){const e=r("DifficultyBadge");return n(),d("div",null,[i(e,{level:"beginner"}),t[0]||(t[0]=o('<h1 id="📝-术语知识测验" tabindex="-1">📝 术语知识测验 <a class="header-anchor" href="#📝-术语知识测验" aria-label="Permalink to &quot;📝 术语知识测验&quot;">​</a></h1><p>学完 AI 术语后，来测试一下你的掌握程度吧！共 7 题，每题后附答案和解析。</p><hr><h2 id="一、选择题" tabindex="-1">一、选择题 <a class="header-anchor" href="#一、选择题" aria-label="Permalink to &quot;一、选择题&quot;">​</a></h2><h3 id="q1-大语言模型-llm-的-上下文窗口-指的是什么" tabindex="-1">Q1：大语言模型（LLM）的&quot;上下文窗口&quot;指的是什么？ <a class="header-anchor" href="#q1-大语言模型-llm-的-上下文窗口-指的是什么" aria-label="Permalink to &quot;Q1：大语言模型（LLM）的&quot;上下文窗口&quot;指的是什么？&quot;">​</a></h3><p>A. 模型运行的硬件环境 B. 模型单次能处理的最大 Token 数 C. 模型训练数据的时间范围 D. 模型能输出的最大字数</p><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>上下文窗口（Context Window）决定了模型一次能&quot;看到&quot;多少内容。窗口越大，能输入的文本越长，多轮对话的记忆也越久。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/context-window.html">上下文窗口</a> · <a href="/ai-knowledge/terms/token.html">Token</a></p></details><hr><h3 id="q2-transformer-架构的核心创新是什么" tabindex="-1">Q2：Transformer 架构的核心创新是什么？ <a class="header-anchor" href="#q2-transformer-架构的核心创新是什么" aria-label="Permalink to &quot;Q2：Transformer 架构的核心创新是什么？&quot;">​</a></h3><p>A. 循环神经网络 B. 卷积计算 C. 自注意力机制 D. 长短期记忆</p><details><summary>查看答案</summary><p><strong>正确答案：C</strong></p><p>自注意力机制（Self-Attention）让模型能够并行处理序列中的每个位置，同时捕捉全局依赖关系。这是 Transformer 区别于 RNN 和 CNN 的关键所在。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/transformer.html">Transformer</a> · <a href="/ai-knowledge/terms/self-attention.html">自注意力机制</a></p></details><hr><h3 id="q3-rag-的中文全称是什么" tabindex="-1">Q3：RAG 的中文全称是什么？ <a class="header-anchor" href="#q3-rag-的中文全称是什么" aria-label="Permalink to &quot;Q3：RAG 的中文全称是什么？&quot;">​</a></h3><p>A. 随机访问生成 B. 检索增强生成 C. 实时分析生成 D. 递归自动生成</p><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>RAG（Retrieval-Augmented Generation，检索增强生成）先从外部知识库中检索相关信息，再让模型基于检索结果生成回答。这种&quot;先查后答&quot;的模式有效减少了幻觉。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/rag.html">RAG</a> · <a href="/ai-knowledge/terms/embedding.html">Embedding</a> · <a href="/ai-knowledge/terms/vector-db.html">向量数据库</a></p></details><hr><h3 id="q4-agent-和普通-llm-最主要的区别是什么" tabindex="-1">Q4：Agent 和普通 LLM 最主要的区别是什么？ <a class="header-anchor" href="#q4-agent-和普通-llm-最主要的区别是什么" aria-label="Permalink to &quot;Q4：Agent 和普通 LLM 最主要的区别是什么？&quot;">​</a></h3><p>A. 参数量更大 B. 能自主调用工具和执行任务 C. 训练数据更多 D. 回答速度更快</p><details><summary>查看答案</summary><p><strong>正确答案：B</strong></p><p>普通 LLM 只能根据输入生成文本，而 Agent 能自主规划、调用工具（搜索、计算、API 等）、观察结果并循环迭代，完成复杂任务。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/agent.html">Agent</a> · <a href="/ai-knowledge/terms/function-calling.html">Function Calling</a> · <a href="/ai-knowledge/terms/mcp.html">MCP</a></p></details><hr><h2 id="二、判断题" tabindex="-1">二、判断题 <a class="header-anchor" href="#二、判断题" aria-label="Permalink to &quot;二、判断题&quot;">​</a></h2><h3 id="q5-fine-tuning-是让模型学习全新的知识-和-training-没有区别。" tabindex="-1">Q5：Fine-tuning 是让模型学习全新的知识，和 Training 没有区别。 <a class="header-anchor" href="#q5-fine-tuning-是让模型学习全新的知识-和-training-没有区别。" aria-label="Permalink to &quot;Q5：Fine-tuning 是让模型学习全新的知识，和 Training 没有区别。&quot;">​</a></h3><details><summary>查看答案</summary><p><strong>❌ 错误</strong></p><p>Fine-tuning（微调）是在预训练模型的基础上，用特定领域的数据进行小幅度调整，让它适应特定任务或风格。它和从零开始的 Training 有本质区别——Fine-tuning 更像是&quot;进修&quot;，而不是&quot;从头学起&quot;。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/fine-tuning.html">微调 (Fine-tuning)</a> · <a href="/ai-knowledge/terms/training-inference.html">训练 / 推理</a></p></details><hr><h3 id="q6-mcp-是-anthropic-提出的开放协议-不是-openai-的私有协议。" tabindex="-1">Q6：MCP 是 Anthropic 提出的开放协议，不是 OpenAI 的私有协议。 <a class="header-anchor" href="#q6-mcp-是-anthropic-提出的开放协议-不是-openai-的私有协议。" aria-label="Permalink to &quot;Q6：MCP 是 Anthropic 提出的开放协议，不是 OpenAI 的私有协议。&quot;">​</a></h3><details><summary>查看答案</summary><p><strong>✅ 正确</strong></p><p>MCP（Model Context Protocol）由 Anthropic 于 2024 年提出并开源，是一个开放的标准化协议，旨在统一 AI 模型与外部工具、数据源之间的交互方式。它不是某个厂商的私有协议。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/mcp.html">MCP</a> · <a href="/ai-knowledge/terms/ai-skills.html">AI Skills</a></p></details><hr><h3 id="q7-embedding-可以把文本转化为向量-语义相近的内容向量距离更近。" tabindex="-1">Q7：Embedding 可以把文本转化为向量，语义相近的内容向量距离更近。 <a class="header-anchor" href="#q7-embedding-可以把文本转化为向量-语义相近的内容向量距离更近。" aria-label="Permalink to &quot;Q7：Embedding 可以把文本转化为向量，语义相近的内容向量距离更近。&quot;">​</a></h3><details><summary>查看答案</summary><p><strong>✅ 正确</strong></p><p>Embedding（嵌入）将文本映射到高维向量空间。语义上相似的内容（如&quot;猫&quot;和&quot;喵星人&quot;）在这个空间中距离更近，而不相关的内容距离更远。这是语义搜索和 RAG 的数学基础。</p><p>💡 关联阅读：<a href="/ai-knowledge/terms/embedding.html">Embedding</a> · <a href="/ai-knowledge/terms/vector-db.html">向量数据库</a></p></details><hr><h2 id="📊-评分" tabindex="-1">📊 评分 <a class="header-anchor" href="#📊-评分" aria-label="Permalink to &quot;📊 评分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>正确数</th><th>等级</th></tr></thead><tbody><tr><td>7</td><td>🏆 满分！术语达人</td></tr><tr><td>5-6</td><td>👍 掌握良好</td></tr><tr><td>3-4</td><td>📖 仍需加强</td></tr><tr><td>0-2</td><td>🔄 建议重读术语篇</td></tr></tbody></table><details><summary>你对了几题？来对答案吧！</summary><table tabindex="0"><thead><tr><th>题号</th><th>答案</th><th>类型</th></tr></thead><tbody><tr><td>Q1</td><td>B</td><td>选择题</td></tr><tr><td>Q2</td><td>C</td><td>选择题</td></tr><tr><td>Q3</td><td>B</td><td>选择题</td></tr><tr><td>Q4</td><td>B</td><td>选择题</td></tr><tr><td>Q5</td><td>❌</td><td>判断题</td></tr><tr><td>Q6</td><td>✅</td><td>判断题</td></tr><tr><td>Q7</td><td>✅</td><td>判断题</td></tr></tbody></table></details>',33))])}const q=a(l,[["render",s]]);export{f as __pageData,q as default};
